// --- Node-RED Function node: Decode & map Dragino RS485-LB/LS uplink (Schneider iEM) ---

const Dev = "ASSET_ID_START_MET_36";

// 1) Schneider mapping in dezelfde volgorde als AT+COMMAND1..7
var channels = [
    { prop: "total_system_power_W", reg: 0x0BF3, id: 4200 }, // Float32 (kW) maar naam blijft _W
    { prop: "total_system_var_VAr", reg: 0x0BFB, id: 4300 }, // Float32 (kVAr)
    { prop: "total_export_kWh", reg: 0xB02D, id: 4500 }, // Float32 (kWh)
    { prop: "total_import_kWh", reg: 0xB02B, id: 4600 }, // Float32 (kWh)
    { prop: "total_export_kVArh", reg: 0xB031, id: 4700 }, // Float32 (kVArh)
    { prop: "total_import_kVArh", reg: 0xB02F, id: 4800 }, // Float32 (kVArh)
    { prop: "total_system_power_factor", reg: 0x0C0B, id: 4400 }, // Float32 (PF)
];

// 2) Geen scaling: units zijn “historisch fout benoemd” maar overal consistent als kW/kVAr
var scaleBy1000 = [];

// 3) Decode Base64-payload naar Buffer
var buf = (typeof msg.payload === "string")
    ? Buffer.from(msg.payload, "base64")
    : msg.payload;

if (!Buffer.isBuffer(buf) || buf.length < 7) {
    node.error("Invalid payload", msg);
    return null;
}

// 4) Lees header en bepaal offset
var HEADER_LEN = 3;
var dataLen = buf.length - HEADER_LEN;
var floatCount = Math.floor(dataLen / 4);

// 5) Helper om een Big-Endian float32 te lezen en afronden
function readF(off) {
    if (off + 4 > buf.length) { return null; }
    var v = buf.readFloatBE(off);
    if (isNaN(v)) { return null; }
    return Math.round(v * 100) / 100;
}

// 6) Decode battery (bytes 0–1) en alle float-slots
var measurements = {
    battery: (((buf[0] << 8) | buf[1]) & 0x7fff) / 1000
};

for (var i = 0; i < floatCount && i < channels.length; i++) {
    var off = HEADER_LEN + i * 4;
    measurements[channels[i].prop] = readF(off);
}

// 7) Bouw de standaardstructuur
var mid = global.get("mid") || 0;

var result = {
    MID: mid,
    D: [{
        Dev: Dev,
        TS: msg.time ? new Date(msg.time).toISOString() : undefined,
        ED: [],
        MD: []
    }]
};

// 8) Vul MD
channels.forEach(function (ch) {
    var val = measurements[ch.prop];
    if (val != null) {
        // scaling blijft leeg, dus dit doet niks
        if (scaleBy1000.indexOf(ch.id) !== -1) {
            val = Math.round((val / 1000) * 1000) / 1000;
        }
        result.D[0].MD.push({ Id: ch.id, Val: val });
    }
});

// batterij
result.D[0].MD.push({ Id: 7200, Val: measurements.battery });

// 9) Optioneel: snr/rssi
[["snr", 5400], ["rssi", 5500]].forEach(function (item) {
    var key = item[0], id = item[1];
    if (msg[key] !== undefined) {
        result.D[0].MD.push({ Id: id, Val: parseFloat(msg[key]) });
    }
});

// spreadFactor uit msg.dr
if (msg.dr && msg.dr.spreadFactor !== undefined) {
    result.D[0].MD.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) });
}

// 10) MID increment + return
global.set("mid", mid + 1);
msg.payload = result;
return msg;
